selector_to_html = {"a[href=\"#id8\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Audio File Playback Service<a class=\"headerlink\" href=\"#id8\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#tts\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Text-to-Speech (TTS)<a class=\"headerlink\" href=\"#tts\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id10\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Safety Notes<a class=\"headerlink\" href=\"#id10\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#def-rossrv-getvolume\"]": "<ul id=\"def-rossrv-getvolume\">\n<li><p><code class=\"docutils literal notranslate\"><span class=\"pre\">GetVolume</span></code> ros2-srv @ /hal/audio/srv/GetVolume.srv</p>\n<div class=\"highlight-perl notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"c1\"># Get Volume</span>\n<span class=\"c1\"># Service: /aimdk_5Fmsgs/srv/GetVolume</span>\n\n<span class=\"c1\"># Request</span>\n<span class=\"n\">CommonRequest</span><span class=\"w\"> </span><span class=\"n\">request</span><span class=\"w\">            </span><span class=\"c1\"># Request header</span>\n\n<span class=\"o\">---</span>\n\n<span class=\"c1\"># Response</span>\n<span class=\"n\">CommonResponse</span><span class=\"w\"> </span><span class=\"n\">reponse</span><span class=\"w\">           </span><span class=\"c1\"># Response header</span>\n<span class=\"n\">uint32</span><span class=\"w\"> </span><span class=\"n\">audio_volume</span><span class=\"w\">              </span><span class=\"c1\"># Current volume (0\u2013100)</span>\n</pre></div>\n</div>\n</li>\n</ul>", "a[href=\"#asr\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Automatic Speech Recognition (ASR) (coming soon)<a class=\"headerlink\" href=\"#asr\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2.1 </span>Voice Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The voice control interface provides a complete set of voice interaction capabilities, including speech synthesis, speech recognition, audio noise reduction, audio playback, and volume control.</strong></p>", "a[href=\"../../example/Cpp.html#cpp-play-media\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.16 </span>Media File Playback<a class=\"headerlink\" href=\"#cpp-play-media\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_media</strong>, enabling playback of specified media files (such as audio files). It supports audio formats including WAV and MP3.</p><p><strong>Features:</strong></p>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Speech Synthesis Services<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#def-rossrv-getmute\"]": "<ul id=\"def-rossrv-getmute\">\n<li><p><code class=\"docutils literal notranslate\"><span class=\"pre\">GetMute</span></code> ros2-srv @ /hal/audio/srv/GetMute.srv</p>\n<div class=\"highlight-perl notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"c1\"># Get Mute Status</span>\n<span class=\"c1\"># Service: /aimdk_5Fmsgs/srv/GetMute</span>\n\n<span class=\"c1\"># Request</span>\n<span class=\"n\">CommonRequest</span><span class=\"w\"> </span><span class=\"n\">request</span><span class=\"w\">            </span><span class=\"c1\"># Request header</span>\n\n<span class=\"o\">---</span>\n\n<span class=\"c1\"># Response</span>\n<span class=\"n\">CommonResponse</span><span class=\"w\"> </span><span class=\"n\">reponse</span><span class=\"w\">           </span><span class=\"c1\"># Response header</span>\n<span class=\"n\">bool</span><span class=\"w\"> </span><span class=\"n\">is_mute</span><span class=\"w\">                     </span><span class=\"c1\"># Current mute state</span>\n</pre></div>\n</div>\n</li>\n</ul>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Key Features<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Text-to-Speech (TTS)<a class=\"headerlink\" href=\"#tts\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id3\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Audio Processing<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"../../faq/temp_works.html#agent-only-voice\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8.1 </span>Disable the Built-in Interaction System and Use Your Own Voice System<a class=\"headerlink\" href=\"#agent-only-voice\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>By default, when the robot is powered on, it automatically enters natural voice interaction mode, and the interaction module occupies the audio input/output streams.</strong> If you need to integrate your own voice system and access the audio streams, you can temporarily disable the built-in interaction module using the steps below. <strong>Future versions will support one-click switching to secondary-development interaction mode to further simplify custom voice system integration.</strong></p>", "a[href=\"#mic-receiver-vad\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">MIC Audio Stream Capture Topic<a class=\"headerlink\" href=\"#mic-receiver-vad\" title=\"Link to this heading\">\uf0c1</a></h2><p>Supports receiving VAD (Voice Activity Detection) events on denoised audio and the corresponding audio stream.</p>", "a[href=\"#id4\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Audio Playback<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#def-rossrv-setmute\"]": "<ul id=\"def-rossrv-setmute\">\n<li><p><code class=\"docutils literal notranslate\"><span class=\"pre\">SetMute</span></code> ros2-srv @ /hal/audio/srv/SetMute.srv</p>\n<div class=\"highlight-perl notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"c1\"># Set Mute</span>\n<span class=\"c1\"># Service: /aimdk_5Fmsgs/srv/SetMute</span>\n\n<span class=\"c1\"># Request</span>\n<span class=\"n\">CommonRequest</span><span class=\"w\"> </span><span class=\"n\">request</span><span class=\"w\">            </span><span class=\"c1\"># Request header</span>\n<span class=\"n\">bool</span><span class=\"w\"> </span><span class=\"n\">is_mute</span><span class=\"w\">                     </span><span class=\"c1\"># Target mute state</span>\n\n<span class=\"o\">---</span>\n\n<span class=\"c1\"># Response</span>\n<span class=\"n\">CommonResponse</span><span class=\"w\"> </span><span class=\"n\">reponse</span><span class=\"w\">           </span><span class=\"c1\"># Response header</span>\n<span class=\"n\">bool</span><span class=\"w\"> </span><span class=\"n\">is_mute</span><span class=\"w\">                     </span><span class=\"c1\"># Current mute state</span>\n</pre></div>\n</div>\n</li>\n</ul>", "a[href=\"#id9\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Programming Examples<a class=\"headerlink\" href=\"#id9\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed programming examples and code descriptions, see:</p>", "a[href=\"#def-rossrv-setvolume\"]": "<ul id=\"def-rossrv-setvolume\">\n<li><p><code class=\"docutils literal notranslate\"><span class=\"pre\">SetVolume</span></code> ros2-srv @ /hal/audio/srv/SetVolume.srv</p>\n<div class=\"highlight-perl notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"c1\"># Set Volume</span>\n<span class=\"c1\"># Service: /aimdk_5Fmsgs/srv/SetVolume</span>\n\n<span class=\"c1\"># Request</span>\n<span class=\"n\">CommonRequest</span><span class=\"w\"> </span><span class=\"n\">request</span><span class=\"w\">            </span><span class=\"c1\"># Request header</span>\n<span class=\"n\">uint32</span><span class=\"w\"> </span><span class=\"n\">audio_volume</span><span class=\"w\">              </span><span class=\"c1\"># Target volume (0\u2013100)</span>\n\n<span class=\"o\">---</span>\n\n<span class=\"c1\"># Response</span>\n<span class=\"n\">CommonResponse</span><span class=\"w\"> </span><span class=\"n\">reponse</span><span class=\"w\">           </span><span class=\"c1\"># Response header</span>\n<span class=\"n\">uint32</span><span class=\"w\"> </span><span class=\"n\">audio_volume</span><span class=\"w\">              </span><span class=\"c1\"># Current volume (0\u2013100)</span>\n</pre></div>\n</div>\n</li>\n</ul>", "a[href=\"#tbl-tts-prioritylevel\"]": "<table class=\"docutils align-default\" id=\"tbl-tts-prioritylevel\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Level</p></th>\n<th class=\"head\"><p>Value</p></th>\n<th class=\"head\"><p>Description</p></th>\n<th class=\"head\"><p>Usage scenarios</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>Emergency safety layer (SAFETY_L10)</p></td>\n<td><p>10</p></td>\n<td><p>Highest priority</p></td>\n<td><p>Safety alerts, emergency notifications</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Warning layer (WARNING_L8)</p></td>\n<td><p>8</p></td>\n<td><p>High priority</p></td>\n<td><p>Hazard alerts and warning messages</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>System notice layer (SYSTEM_L7)</p></td>\n<td><p>7</p></td>\n<td><p>Medium-high priority</p></td>\n<td><p>System-level Notice</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Interaction response layer (INTERACTION_L6)</p></td>\n<td><p>6</p></td>\n<td><p>Medium priority</p></td>\n<td><p>User interaction and conversational responses</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Mission execution layer (MISSION_L4)</p></td>\n<td><p>4</p></td>\n<td><p>Medium-low priority</p></td>\n<td><p>Task execution and status broadcasts</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Service layer (SERVICE_L2)</p></td>\n<td><p>2</p></td>\n<td><p>Low priority</p></td>\n<td><p>Proactive services and reminders</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Background service layer (BACKGROUND_L1)</p></td>\n<td><p>1</p></td>\n<td><p>Lowest priority</p></td>\n<td><p>Background services and logging</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#def-rosmsg-playttsresponse\"]": "<ul id=\"def-rosmsg-playttsresponse\">\n<li><p><code class=\"docutils literal notranslate\"><span class=\"pre\">PlayTtsResponse</span></code> ros2-msg @ interaction/msg/PlayTtsResponse.msg</p>\n<div class=\"highlight-perl notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"c1\"># Embedded response msg</span>\n<span class=\"n\">string</span><span class=\"w\"> </span><span class=\"n\">text</span><span class=\"w\">                      </span><span class=\"c1\"># Response text</span>\n<span class=\"n\">TtsPriorityLevel</span><span class=\"w\"> </span><span class=\"n\">priority_level</span><span class=\"w\">  </span><span class=\"c1\"># Priority level</span>\n<span class=\"n\">uint32</span><span class=\"w\"> </span><span class=\"n\">priority_weight</span><span class=\"w\">           </span><span class=\"c1\"># Priority weight</span>\n<span class=\"n\">string</span><span class=\"w\"> </span><span class=\"n\">domain</span><span class=\"w\">                    </span><span class=\"c1\"># Caller domain</span>\n<span class=\"n\">string</span><span class=\"w\"> </span><span class=\"n\">trace_id</span><span class=\"w\">                  </span><span class=\"c1\"># Request trace ID</span>\n<span class=\"n\">bool</span><span class=\"w\"> </span><span class=\"n\">is_success</span><span class=\"w\">                  </span><span class=\"c1\"># Whether the request succeeded</span>\n<span class=\"n\">string</span><span class=\"w\"> </span><span class=\"n\">error_message</span><span class=\"w\">             </span><span class=\"c1\"># Error message</span>\n<span class=\"n\">uint32</span><span class=\"w\"> </span><span class=\"n\">estimated_duration</span><span class=\"w\">        </span><span class=\"c1\"># Estimated duration (ms)</span>\n</pre></div>\n</div>\n</li>\n</ul>", "a[href=\"../../example/Cpp.html#cpp-play-tts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.17 </span>TTS (Text-to-Speech)<a class=\"headerlink\" href=\"#cpp-play-tts\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_tts</strong>, enabling the robot to speak the provided text. Users can input any text depending on the scenario.</p><p><strong>Features:</strong></p>", "a[href=\"../../example/Cpp.html#cpp-mic-receiver\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.18 </span>Microphone Audio Reception<a class=\"headerlink\" href=\"#cpp-mic-receiver\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mic_receiver</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/agent/process_audio_output</span></code> topic to receive the robot\u2019s noise-reduced audio stream. It supports both internal and external microphone audio streams, and automatically saves complete speech segments as PCM files based on VAD (Voice Activity Detection) states.</p><p><strong>Features:</strong></p>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Volume Control Services<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id5\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Volume Control<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
